// src/components/PaymentModal.js
import React, { useEffect, useState } from "react";
import styles from "./PaymentModal.module.css";

// Generates UPI QR using Google Charts API
const UPI_ID     = "7725813053@ybl";
const AMOUNT     = "10";
const UPI_NAME   = "AssignmentAI";
const UPI_NOTE   = "Assignment Download Fee";

function getUpiUrl() {
  return `upi://pay?pa=${UPI_ID}&pn=${encodeURIComponent(UPI_NAME)}&am=${AMOUNT}&cu=INR&tn=${encodeURIComponent(UPI_NOTE)}`;
}

function getQrImageUrl() {
  const upiUrl = getUpiUrl();
  return `https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=${encodeURIComponent(upiUrl)}`;
}

export default function PaymentModal({ onConfirm, onClose }) {
  const [confirmed, setConfirmed] = useState(false);
  const [timer, setTimer]         = useState(0);

  // Start a timer so user sees QR for at least a few seconds
  useEffect(() => {
    const interval = setInterval(() => {
      setTimer((t) => t + 1);
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  const handleConfirm = () => {
    setConfirmed(true);
    setTimeout(() => {
      onConfirm(); // trigger actual download
    }, 500);
  };

  return (
    <div className={styles.overlay}>
      <div className={styles.modal}>
        {/* Close button */}
        <button className={styles.closeBtn} onClick={onClose}>✕</button>

        <div className={styles.header}>
          <span className={styles.icon}>💳</span>
          <h2>Pay to Download</h2>
          <p>Scan the QR code to pay <strong>₹{AMOUNT}</strong></p>
        </div>

        {/* QR Code */}
        <div className={styles.qrBox}>
          <img
            src={getQrImageUrl()}
            alt="UPI Payment QR"
            className={styles.qrImage}
          />
          <p className={styles.upiId}>UPI: {UPI_ID}</p>
        </div>

        {/* Payment apps */}
        <div className={styles.apps}>
          <span>Pay using</span>
          <div className={styles.appList}>
            <span>GPay</span>
            <span>PhonePe</span>
            <span>Paytm</span>
            <span>Any UPI</span>
          </div>
        </div>

        <div className={styles.divider}>
          <span>After payment</span>
        </div>

        {/* Confirm button */}
        {!confirmed ? (
          <button
            className={styles.confirmBtn}
            onClick={handleConfirm}
            disabled={timer < 5}
          >
            {timer < 5
              ? `Please wait ${5 - timer}s...`
              : "✅ I have paid — Download Now"}
          </button>
        ) : (
          <div className={styles.downloading}>⏳ Starting download...</div>
        )}

        <p className={styles.note}>
          ⚠️ Click the button only after completing payment
        </p>
      </div>
    </div>
  );
}
